import type { FlashcardData } from '@/types'

/** Mobile Development (concept-first, framework-agnostic) flashcard deck keyed by topic id. */
export const MOBILE_FLASHCARDS: FlashcardData = {
  // ─── P0 · Foundations ───────────────────────────────────────────────────────
  'what-is-mobile': [
    { id: 'mbfc_whatis_1', q: 'What actually makes mobile development different from web or desktop?', a: "Constraints, not the language. A phone is a battery-powered, sometimes-connected, sensor-rich device the OS can suspend or kill at any moment to protect memory and battery. You are a guest in a tightly managed environment: limited RAM, a strict process lifecycle, background execution limits, and permission-gated hardware. Master those constraints and any framework becomes a detail.", hint: 'Think about what the OS can do TO your app.' },
    { id: 'mbfc_whatis_2', q: 'Why is thinking in frameworks (Flutter vs React Native vs native) the wrong starting point?', a: "Because every framework ultimately talks to the same two operating systems and obeys the same rules: the Android/iOS lifecycle, the single UI thread, the frame budget, the permission model, and background limits. Frameworks differ in ergonomics and rendering strategy, but the underlying platform behavior they must respect is identical. Learn the platform and you can pick up any framework in days." },
    { id: 'mbfc_whatis_3', q: 'What are the core resource constraints a mobile app must respect?', a: "Battery (every wakeup, radio use, and GPS fix costs power), memory (background apps get killed first under pressure), CPU/thermals (sustained load throttles and drains), network (metered, high-latency, and intermittent), and the screen (small, touch-first, wildly varying sizes/densities). Good mobile engineering is largely resource budgeting." },
    { id: 'mbfc_whatis_4', q: 'Why does the OS, not your app, ultimately control your app’s fate?', a: "The OS owns memory, battery, and scheduling for the whole device. To keep the foreground app smooth, it will freeze, deprioritize, or terminate background apps without warning, deny wakeups, and revoke resources. Your app cannot assume it keeps running when backgrounded — it must save state proactively and recover gracefully. This single fact drives most of mobile architecture." },
  ],
  'mobile-os-architecture': [
    { id: 'mbfc_osarch_1', q: 'Describe the layered architecture shared by Android and iOS.', a: "Bottom to top: a Linux (Android) or Darwin/XNU (iOS) kernel; a hardware abstraction and driver layer; system services/daemons (window/activity manager, media, connectivity) running as privileged processes; framework APIs your app links against; and your app running in its own sandboxed process. Your code never touches hardware directly — it requests it through system services via IPC." },
    { id: 'mbfc_osarch_2', q: 'How does your app talk to system services like the camera or GPS?', a: "Through inter-process communication (IPC) to privileged system daemons — Binder on Android, XPC/Mach ports on iOS. You call a framework API, which marshals the request across a process boundary to a service that actually owns the hardware, checks your permissions, and returns a handle or data. This boundary is where permission enforcement and isolation happen." },
    { id: 'mbfc_osarch_3', q: 'What is a system service and why do apps rely on them?', a: "A long-lived privileged process that manages a shared resource on behalf of all apps: the ActivityManager/WindowManager, LocationManager, connectivity, notifications, media. Centralizing them lets the OS enforce policy (permissions, battery limits), arbitrate contention (only one app uses the camera at a time), and keep apps sandboxed away from hardware and each other." },
    { id: 'mbfc_osarch_4', q: 'Android vs iOS at the architecture level — what are the key differences?', a: "Android: Linux kernel, apps historically on a managed runtime (ART), Binder IPC, an open component model with intents and multiple app entry points, many OEMs and versions (fragmentation). iOS: Darwin/XNU kernel, apps compiled to native ARM, XPC/Mach IPC, a tighter app model with fewer entry points, and Apple controlling both hardware and OS (uniformity). The philosophies — open/flexible vs curated/consistent — explain most API differences." },
  ],
  'app-sandbox-model': [
    { id: 'mbfc_sandbox_1', q: 'What is the app sandbox and what does it isolate?', a: "Each app runs as its own OS user/process with a private data directory no other app can read. The sandbox isolates your files, memory, and default capabilities. To touch anything shared — camera, contacts, location, other apps’ data — you must go through a permission-gated system API. The sandbox is the primary security and privacy boundary on mobile.", hint: 'One app, one walled garden.' },
    { id: 'mbfc_sandbox_2', q: 'Where can an app safely store data, and who else can see it?', a: "In its private sandbox directory (app-internal storage), readable only by that app; the OS wipes it on uninstall. Anything written to shared/external storage or shared containers is visible to other apps or the user and needs permissions. On both platforms, sensitive secrets belong in the hardware-backed keystore (Android Keystore / iOS Keychain), never in plain app files." },
    { id: 'mbfc_sandbox_3', q: 'How do sandboxed apps share data with each other if they cannot read each other’s files?', a: "Through OS-mediated channels: Android uses intents, content providers, and FileProvider URIs with granted permissions; iOS uses share extensions, App Groups (shared containers for apps from the same team), universal links, and document/UTI-based sharing. Every path is brokered by the OS so isolation and permissions stay enforced." },
    { id: 'mbfc_sandbox_4', q: 'Why does uninstalling an app cleanly remove its data, and what is the exception?', a: "Because the app’s sandbox directory is owned by the OS and deleted with the app. Exceptions are data the app deliberately wrote outside its sandbox (shared media, cloud backups, server-side accounts) and, on iOS, Keychain items which can persist across reinstalls unless explicitly cleared — a common cause of ‘logged in after reinstall’ surprises." },
  ],
  'native-vs-crossplatform': [
    { id: 'mbfc_nvx_1', q: 'What are the three broad ways to build a mobile app, and how do they render?', a: "1) Native (Kotlin/Swift): call platform UI toolkits directly. 2) Cross-platform with native widgets (React Native): your logic runs in a JS engine and drives real native views over a bridge. 3) Cross-platform with own rendering (Flutter): ships its own engine (Skia/Impeller) and paints every pixel itself, bypassing native widgets. All three still obey the same OS lifecycle and limits." },
    { id: 'mbfc_nvx_2', q: 'What do you actually trade away by going cross-platform?', a: "Directness. You gain one codebase and faster shared iteration; you pay with an abstraction layer that can lag new OS features, add startup/runtime overhead, complicate debugging across the bridge, and occasionally force you to write native modules anyway for platform-specific hardware or performance. The trade is team velocity vs low-level control and immediacy." },
    { id: 'mbfc_nvx_3', q: 'Why do React Native and Flutter take fundamentally different rendering approaches?', a: "React Native maps its component tree to real native widgets, so it looks natively correct for free but must cross a JS–native boundary. Flutter renders its own widgets onto a canvas via its engine, giving pixel-identical, highly controllable UI across platforms at the cost of not being real native views (accessibility and platform look must be re-implemented). Neither escapes the platform lifecycle or frame budget." },
    { id: 'mbfc_nvx_4', q: 'How should a team actually choose native vs cross-platform?', a: "Match the constraint that dominates: deep hardware/OS integration, max performance, or platform-specific UX → native. Shared business logic, small team, fast time-to-market across both stores → cross-platform. Also weigh existing team skills, hiring, and how much the app leans on bleeding-edge OS features. There is no universally right answer — only the right fit for the constraints and team." },
  ],

  // ─── P1 · App & Screen Lifecycle ─────────────────────────────────────────────
  'app-launch-types': [
    { id: 'mbfc_launch_1', q: 'Cold, warm, and hot start — what is the difference and why care?', a: "Cold: the process does not exist; the OS forks a new process, initializes the runtime and app, then builds the first screen — slowest. Warm: the process is alive but the target screen must be recreated. Hot: the app is fully in memory and just returns to the foreground — near-instant. Cold start is your perceived launch speed and the one you optimize.", hint: 'How much already lives in memory?' },
    { id: 'mbfc_launch_2', q: 'What happens during a cold start, step by step?', a: "OS creates the process and loads the runtime → the app entry point / Application object initializes (DI, SDKs, logging) → the first screen is constructed, laid out, and drawn → real data loads. Every SDK you initialize eagerly and every synchronous call on this path delays the first frame. Cold-start work is the single biggest lever on launch time." },
    { id: 'mbfc_launch_3', q: 'Why is heavy work in the app entry point (Application/AppDelegate) so damaging?', a: "It runs on the main thread on the critical cold-start path before any screen appears, so every millisecond directly delays first frame and time-to-interactive. Analytics, crash SDKs, and DI initialized eagerly here stack up. The fix: defer non-critical initialization, do it lazily or off the main thread, and initialize only what the first screen truly needs." },
    { id: 'mbfc_launch_4', q: 'What is a splash/launch screen actually for on mobile?', a: "To fill the unavoidable gap between process start and the first real frame with something branded, so launch feels instant instead of blank/frozen. On Android the system launch theme and the Splash Screen API cover the window before your UI exists; iOS requires a launch storyboard. It hides latency — it does not remove it, so still optimize the real work behind it." },
  ],
  'app-lifecycle-states': [
    { id: 'mbfc_lifecycle_1', q: 'What are the core app lifecycle states every mobile OS models?', a: "Not-running → foreground/active (visible and receiving input) → inactive/paused (visible but not focused, e.g. a call overlay or app switcher) → background (not visible, briefly running) → suspended/stopped (frozen, may be terminated). The app transitions as the user and OS move it, and it can be killed from the background at any time.", hint: 'Visible? Focused? Still in memory?' },
    { id: 'mbfc_lifecycle_2', q: 'Which lifecycle callback should you use to save critical state, and why?', a: "The one fired as you leave the foreground — onPause/onStop on Android, sceneWillResignActive/didEnterBackground on iOS — because it is the last guaranteed moment before the OS may suspend or kill you without further callbacks. Persist unsaved user input and essential state there; never assume a later ‘onDestroy’ will run, because a killed process gets no final callback." },
    { id: 'mbfc_lifecycle_3', q: 'What can and cannot your app do once it enters the background?', a: "It gets a short window to finish work, then is frozen. You cannot assume timers, network calls, or CPU work continue — they may be paused mid-flight. For real background work you must use the OS-sanctioned mechanisms (WorkManager/JobScheduler, BGTaskScheduler, foreground services, push) rather than hoping your normal code keeps running. Backgrounded means ‘about to be suspended.’" },
    { id: 'mbfc_lifecycle_4', q: 'Why should lifecycle logic live in a lifecycle-aware component rather than scattered in the UI?', a: "Because resources tied to visibility — location updates, sensors, camera, observers, animations — must start when the screen is active and stop when it is not, or they leak memory and drain battery. Centralizing start/stop in a lifecycle-aware owner (Android Lifecycle/ViewModel, iOS view controller callbacks) guarantees symmetric setup/teardown and prevents work continuing on invisible screens." },
  ],
  'process-death-restoration': [
    { id: 'mbfc_procdeath_1', q: 'What is background process death and why is it not a crash?', a: "When the OS needs memory or battery, it silently terminates backgrounded app processes — no crash, no user error, just gone. When the user returns, the OS starts a fresh process and expects your app to look like the user never left. It is normal, expected behavior; designing as if the process always survives is a top source of bugs.", hint: 'The OS reclaiming memory, not a bug.' },
    { id: 'mbfc_procdeath_2', q: 'Why is in-memory state (a variable, a singleton) unsafe across backgrounding?', a: "Because process death wipes all memory. Anything held only in RAM — the current user object, a loaded list, in-progress form input, navigation position — is lost when the OS kills and later recreates the process. Only data you persisted (disk, saved instance state, server) survives. Treat memory as volatile scratch space, not durable storage." },
    { id: 'mbfc_procdeath_3', q: 'How do Android and iOS help you restore UI state after process death?', a: "Android provides saved instance state / SavedStateHandle (a small bundle persisted by the OS and handed back on recreation) plus rebuildable back stacks. iOS provides state restoration (encode/decode UI state, and NSUserActivity for handoff/continuation). Both give you a small, serializable place to stash ‘where the user was’ so you can reconstruct the screen, not the whole app." },
    { id: 'mbfc_procdeath_4', q: 'What is the practical rule for state that must survive process death?', a: "Save small, transient UI state (scroll position, form fields, selected tab) to the OS saved-state bundle; save durable data to disk or a local database; keep the server as source of truth for anything critical. Reserve in-memory state only for what you can cheaply recompute. The test: kill the app from the background and relaunch — the user should land exactly where they were." },
  ],
  'main-ui-thread': [
    { id: 'mbfc_uithread_1', q: 'Why is there a single main/UI thread, and what is its job?', a: "UI toolkits are not thread-safe, so one thread owns all view creation, updates, input handling, and drawing to keep them consistent. It runs an event loop pulling from a message queue: input events, layout passes, and your callbacks. Everything the user sees flows through this one thread — which is exactly why you must never block it.", hint: 'One loop, one queue, all the UI.' },
    { id: 'mbfc_uithread_2', q: 'What happens if you do heavy work on the main thread?', a: "The event loop cannot process the next frame or input, so the UI freezes: dropped frames (jank), unresponsive taps, and on Android an ANR (‘Application Not Responding’) or on iOS a watchdog kill if it stalls too long. Anything slow — disk, network, JSON parsing, image decode, crypto — must move off the main thread." },
    { id: 'mbfc_uithread_3', q: 'What is the golden rule for main-thread vs background work?', a: "Do work on background threads; touch the UI only on the main thread. Run I/O, parsing, and computation off-main, then hop back to the main thread to apply results to the UI. Frameworks encode this: Kotlin coroutine dispatchers (IO vs Main), Swift async/await with the main actor, RN’s JS thread plus native modules, Flutter isolates. Violating either half causes freezes or crashes." },
    { id: 'mbfc_uithread_4', q: 'Why can’t you just update the UI from a background thread to save a hop?', a: "Because UI toolkits require all view access on the main thread; touching views from another thread causes crashes or silent corruption (Android throws CalledFromWrongThreadException; iOS UIKit is main-thread-only). The rule is asymmetric on purpose: compute anywhere, but mutate the UI only on the one thread that owns it." },
  ],

  // ─── P2 · Rendering & UI Fundamentals ────────────────────────────────────────
  'frame-rendering-pipeline': [
    { id: 'mbfc_render_1', q: 'What are the stages that turn your UI code into pixels each frame?', a: "Measure (how big does each element want to be) → layout (position everything in the tree) → draw/record (produce drawing commands) → rasterize (turn commands into a bitmap, usually on the GPU) → composite (combine layers and hand the buffer to the display). This runs every frame; work at any stage counts against the frame budget.", hint: 'measure → layout → draw → raster → composite' },
    { id: 'mbfc_render_2', q: 'Where does the CPU work vs the GPU work in the pipeline?', a: "CPU handles measure, layout, and recording draw commands (plus your app logic and state diffing). The GPU handles rasterization and compositing of layers. A frame drops if EITHER is too slow: a deep/complex layout starves the CPU; overdraw, large textures, or many blended layers starve the GPU. Profiling means finding which side is the bottleneck." },
    { id: 'mbfc_render_3', q: 'What is compositing and why does it matter for smooth animation?', a: "Compositing merges independently rendered layers (with transforms, opacity, clipping) into the final image. Properties that only affect compositing — translate, scale, opacity of an existing layer — can animate on the GPU without re-running layout or paint, so they stay smooth. Animating properties that force re-layout (width, adding elements) is far more expensive." },
    { id: 'mbfc_render_4', q: 'Why does the platform double/triple buffer and sync to VSync?', a: "The display refreshes at a fixed rate (e.g. 60/90/120 Hz). VSync signals when a new frame is needed; the GPU draws into a back buffer while the front buffer shows on screen, then they swap. This prevents tearing and paces rendering. Your job is to finish the whole pipeline within one VSync interval so no frame is missed." },
  ],
  'frame-budget-jank': [
    { id: 'mbfc_jank_1', q: 'What is the frame budget and where does the 16ms number come from?', a: "At 60Hz the display asks for a new frame every ~16.7ms, so ALL per-frame work — your logic, layout, paint, and the GPU’s share — must fit in that window. At 90Hz it is ~11ms, at 120Hz ~8ms. Miss it and the previous frame shows again: a dropped frame. The budget shrinks as refresh rate rises.", hint: '1000ms / 60 ≈ 16.7ms.' },
    { id: 'mbfc_jank_2', q: 'What is jank and how does it differ from low average FPS?', a: "Jank is visible stutter from individual missed frames — a hitch during a scroll or animation. Average FPS can look fine (say 58) while occasional 40ms frames make it feel broken. Users perceive the worst frames, not the average, so smoothness is about frame-time consistency and eliminating spikes, not maximizing an average." },
    { id: 'mbfc_jank_3', q: 'What are the usual causes of dropped frames during scrolling?', a: "Doing too much per frame on the row that scrolls in: synchronous image decode, layout of deep view trees, allocations that trigger GC pauses, main-thread I/O, or rebuilding views instead of recycling them. The fix: recycle/virtualize rows, decode and prepare data off the main thread, keep per-item bind work tiny, and avoid main-thread allocations in the scroll path." },
    { id: 'mbfc_jank_4', q: 'How do you diagnose whether jank is CPU-bound or GPU-bound?', a: "Use frame profilers (Android GPU rendering / Perfetto / Systrace, iOS Instruments Core Animation & Time Profiler, Flutter DevTools timeline). Long ‘build/layout’ or main-thread segments → CPU-bound (simplify the tree, move work off-main). Long GPU/raster segments with overdraw → GPU-bound (reduce layers, blending, texture size). Measure first; never guess." },
  ],
  'imperative-vs-declarative-ui': [
    { id: 'mbfc_impdec_1', q: 'What is the core difference between imperative and declarative UI?', a: "Imperative: you hold references to views and mutate them step by step (label.text = x; button.enabled = false) in response to events — you manage transitions. Declarative: you write a function of state that describes what the UI should look like for the current state, and the framework computes and applies the differences. You describe the destination, not the steps.", hint: 'Mutate views vs describe UI = f(state).' },
    { id: 'mbfc_impdec_2', q: 'Why did the industry shift toward declarative UI (Compose, SwiftUI, React, Flutter)?', a: "Imperative UI gets buggy as state grows: every event must correctly update every dependent view, and missed transitions cause inconsistent screens. Declarative UI makes the current state the single source of truth and regenerates the view from it, eliminating whole classes of ‘forgot to update that label’ bugs and making UI predictable and testable as a pure function of state." },
    { id: 'mbfc_impdec_3', q: 'If declarative UI ‘rebuilds’ on every state change, why isn’t it slow?', a: "It does not literally repaint everything. The framework builds a lightweight description, diffs it against the previous one, and mutates only the real views that actually changed (React/RN reconciliation, Compose recomposition, SwiftUI diffing). The rebuild is cheap virtual work; the expensive real-view updates are minimized to the actual delta." },
    { id: 'mbfc_impdec_4', q: 'What new responsibility does declarative UI put on the developer?', a: "Modeling state well. Since UI is a pure function of state, correctness and performance hinge on structuring state cleanly and scoping updates so only the affected subtree re-evaluates. Poorly scoped state causes over-recomposition/re-render (performance) or stale UI (correctness). The skill shifts from wiring view mutations to designing state and keys/dependencies." },
  ],
  'list-virtualization': [
    { id: 'mbfc_virt_1', q: 'Why can’t a long scrollable list just create a view for every item?', a: "Thousands of item views would exhaust memory and take far too long to lay out, blowing the frame budget and likely getting the app killed. Only a screenful is visible at once, so materializing off-screen items is pure waste. Every mobile list toolkit therefore virtualizes: it renders only what is visible plus a small buffer.", hint: 'Only a screenful is ever visible.' },
    { id: 'mbfc_virt_2', q: 'What is view recycling and how does it keep scrolling smooth?', a: "As an item scrolls off screen, its view object is reused to display the item scrolling on — only its data (bind) is updated, not its structure. This keeps a small fixed pool of views regardless of list length, avoiding constant allocation and layout. Android RecyclerView, iOS UITableView/UICollectionView reuse, RN FlatList windowing, and Flutter ListView.builder all do this." },
    { id: 'mbfc_virt_3', q: 'What common mistakes make a virtualized list janky anyway?', a: "Heavy work in the bind/build of each row: synchronous image decode, complex nested layouts, per-row allocations, or recomputing data on every bind. Also not providing stable keys/ids (forcing rebuilds), variable/unmeasured row heights causing re-layout, and loading full-resolution images. Keep bind O(1) and cheap; do expensive prep off the main thread and cache it." },
    { id: 'mbfc_virt_4', q: 'Why do lists need stable item ids/keys?', a: "So the framework can tell which items moved, were inserted, or removed and reuse/animate the right views instead of rebuilding everything. Stable ids enable efficient diffing (DiffUtil, React keys, SwiftUI Identifiable), correct recycling, and smooth insert/remove animations. Using array index as a key breaks this the moment the list reorders." },
  ],

  // ─── P3 · Screens, Navigation & Adaptation ──────────────────────────────────
  'screen-diversity': [
    { id: 'mbfc_screendiv_1', q: 'What dimensions of screen diversity must a mobile UI handle?', a: "Physical size (small phones to tablets to foldables), resolution and pixel density (dpi/ppi), aspect ratio, safe areas (notches, punch-holes, rounded corners, home indicator), orientation, and dynamic type/font scaling for accessibility. You are never designing for one screen — you design a layout that adapts across a continuous range.", hint: 'Size, density, aspect, safe areas, orientation.' },
    { id: 'mbfc_screendiv_2', q: 'What are safe areas and insets, and why must you respect them?', a: "Safe area is the region not covered by system UI or hardware cutouts — status bar, notch, navigation bar, home indicator, rounded corners. Insets tell you how much to pad. If you draw interactive content into unsafe regions it gets clipped or hidden behind the notch or gesture bar. Always lay out relative to safe-area insets, never fixed offsets." },
    { id: 'mbfc_screendiv_3', q: 'Why must you never hardcode pixel sizes for layout?', a: "Because devices differ wildly in density and size, so a fixed pixel value looks tiny on one screen and huge on another. Use density-independent units (dp/pt) and relative/constraint-based layout so the system scales UI to the physical device. Hardcoded pixels also fight the user’s font-scale and display-size accessibility settings." },
    { id: 'mbfc_screendiv_4', q: 'How do foldables and tablets change layout thinking?', a: "They introduce large and changing window sizes, hinges/folds, and multi-window/split-screen, so a phone layout stretched wide looks broken. You design responsive layouts keyed off available width/size classes — showing master-detail or multi-pane on large windows and a single column on phones — and handle the window resizing as a first-class configuration change, not an edge case." },
  ],
  'responsive-adaptive-layout': [
    { id: 'mbfc_resp_1', q: 'What is the difference between responsive and adaptive layout on mobile?', a: "Responsive: one flexible layout that fluidly stretches/reflows to fit any size (flexbox, constraints, percentages). Adaptive: distinct layouts chosen at breakpoints/size classes (a phone layout vs a tablet master-detail layout). Real apps combine both — responsive within a size class, adaptive across major breakpoints.", hint: 'Fluidly stretch vs swap layouts at breakpoints.' },
    { id: 'mbfc_resp_2', q: 'What are size classes / window size classes and why use them?', a: "Coarse buckets of available window size (e.g. compact vs expanded width) that abstract away exact device models. You branch layout on the size class — single column when compact, two-pane when expanded — so the same code adapts to phones, tablets, foldables, and split-screen without hardcoding device checks. iOS uses trait/size classes; Android uses WindowSizeClass." },
    { id: 'mbfc_resp_3', q: 'Why base layout decisions on available window size, not device type?', a: "Because a ‘phone’ can be in split-screen (small window) and a ‘tablet’ app can be a thin side pane; multi-window and foldables break the device=size assumption. Reacting to the actual window size the OS gives you keeps the UI correct in every configuration, including resizes at runtime, rather than guessing from an unreliable device category." },
    { id: 'mbfc_resp_4', q: 'What is a master-detail (list-detail) pattern and when do you use it?', a: "A layout showing a list and the selected item’s detail. On a small window they are two separate screens (tap list → push detail); on a large window they sit side by side in one screen. It is the canonical adaptive pattern for using extra width on tablets/foldables while degrading gracefully to stacked navigation on phones." },
  ],
  'navigation-models': [
    { id: 'mbfc_nav_1', q: 'What is a navigation back stack and why is it central to mobile?', a: "A stack of screens: navigating pushes a screen on top, back pops it off. It models the user’s path so the system back gesture/button returns them predictably. Because the OS can kill and recreate your app, the stack must be reconstructible from saved state — navigation is stateful, and getting the back stack right is core UX.", hint: 'Push to go deeper, pop to go back.' },
    { id: 'mbfc_nav_2', q: 'Compare the main navigation patterns: stack, tabs, and drawer/modal.', a: "Stack: linear drill-down with back (detail flows). Tabs: parallel top-level sections, each often with its own stack, switched without losing place. Drawer: a slide-out menu for many/less-frequent destinations. Modal/sheet: a temporary focused task layered over the current context. Most apps compose these — tabs at the root, stacks within, modals for tasks." },
    { id: 'mbfc_nav_3', q: 'Why should navigation state be modeled as data, not imperative calls scattered in UI?', a: "Because it must be saved and restored across process death, deep-linked into, and tested. Treating the back stack as declarative state (a list of destinations) lets the framework serialize it, reconstruct arbitrary stacks for a deep link, and keep navigation predictable. Ad-hoc ‘push this screen here’ calls make restoration and deep linking painful." },
    { id: 'mbfc_nav_4', q: 'How should the hardware/system back gesture behave, and why is it tricky?', a: "It should undo the last navigation step within your app and, at a stack root, hand control back to the OS (leaving the app). Trickiness: modals, nested stacks, tab back-stacks, and in-progress forms all need correct back handling, and Android’s predictive back and iOS’s edge-swipe expect consistent, reversible navigation. Mishandling back is one of the most common UX complaints." },
  ],
  'deep-linking-mobile': [
    { id: 'mbfc_deeplink_1', q: 'What is a deep link and what problem does it solve?', a: "A URL or URI that opens a specific screen/state inside an app rather than just launching it — e.g. a notification, email, or web link that jumps straight to a product page. It solves entry from outside the app: marketing, sharing, notifications, and web-to-app continuity all need to land the user on the right in-app destination.", hint: 'A URL that lands inside the app.' },
    { id: 'mbfc_deeplink_2', q: 'What is the difference between custom-scheme deep links and universal/app links?', a: "Custom scheme (myapp://path) is app-defined but unverified — any app can claim it and it fails gracefully to nothing if the app is absent. Universal Links (iOS) and App Links (Android) use real https URLs verified via a domain association file, so the OS trusts them, they fall back to the website if the app is not installed, and they cannot be hijacked. Prefer verified https links." },
    { id: 'mbfc_deeplink_3', q: 'Why must a deep link rebuild a sensible back stack, not just show one screen?', a: "If a link drops the user onto a deep detail screen with no way back into the app’s hierarchy, pressing back exits the app abruptly. Correct handling synthesizes the appropriate parent stack (home → category → product) so the user can navigate up naturally. Deep linking is as much about reconstructing context as about reaching the target screen." },
    { id: 'mbfc_deeplink_4', q: 'What is deferred deep linking and when do you need it?', a: "When the target app is not installed: the link sends the user to the store, and after install the app reads the original intended destination and routes there on first launch. It preserves the user’s intent across the install gap — essential for attribution and onboarding funnels — and requires storing the link context through the install (via referrer/clipboard/attribution SDKs)." },
  ],

  // ─── P4 · State & Local Data ─────────────────────────────────────────────────
  'state-types': [
    { id: 'mbfc_statetypes_1', q: 'What are the different kinds of state in a mobile app?', a: "UI/ephemeral state (scroll position, toggles, text-in-progress) that dies with the screen; app/session state (logged-in user, cart) that spans screens; persistent local state (cached data, settings) on disk; and server state (the remote source of truth) mirrored locally. Each has different lifetime, ownership, and durability needs — conflating them causes bugs.", hint: 'Different lifetimes: screen, session, disk, server.' },
    { id: 'mbfc_statetypes_2', q: 'Why does distinguishing UI state from server state matter so much?', a: "They have opposite characteristics: UI state is owned by the client, cheap, and transient; server state is owned remotely, can change under you, and needs syncing/caching/invalidation. Treating cached server data as if the client owns it causes stale UI and conflicts; treating UI state as if the server owns it adds needless network coupling. Clear boundaries drive clean architecture." },
    { id: 'mbfc_statetypes_3', q: 'Where should each kind of state live to survive the lifecycle correctly?', a: "Ephemeral UI state → the lifecycle-scoped holder plus saved-instance-state for process death (survives config changes and rotation). Session state → an app-scoped holder, re-fetched or restored on cold start. Persistent state → disk (key-value, files, database). Server state → fetched and cached locally with an explicit source-of-truth policy. Placing state at the wrong scope causes leaks or loss." },
    { id: 'mbfc_statetypes_4', q: 'What is a single source of truth and why does it reduce bugs?', a: "The principle that each piece of state has exactly one authoritative owner, and everything else derives/observes from it rather than keeping its own copy. Duplicated state drifts out of sync (the classic ‘the badge says 3 but the list shows 2’). One source, observed reactively, guarantees every part of the UI reflects the same value." },
  ],
  'keyvalue-file-storage': [
    { id: 'mbfc_kvfile_1', q: 'What is key-value storage on mobile and what is it for?', a: "A small persistent dictionary for simple settings and flags — Android SharedPreferences/DataStore, iOS UserDefaults. Ideal for user preferences, feature toggles, onboarding-seen flags, and last-selected values. It is not a database: no queries, no relations, and it loads wholesale, so it is wrong for large or structured data.", hint: 'A tiny persistent dictionary for settings.' },
    { id: 'mbfc_kvfile_2', q: 'When should you use plain files vs key-value vs a database?', a: "Files: blobs and documents — images, downloaded media, exported/imported data, caches of large payloads. Key-value: a handful of small primitive settings. Database: structured, queryable, relational, or large collections you filter/sort/paginate. Choosing by data shape (blob vs setting vs queryable records) avoids abusing key-value stores as makeshift databases." },
    { id: 'mbfc_kvfile_3', q: 'Why is storing secrets in key-value stores a mistake, and what is the fix?', a: "SharedPreferences/UserDefaults are plain, unencrypted app storage — readable on a rooted/jailbroken device or via backups. Tokens, keys, and passwords belong in the hardware-backed secure store: Android Keystore/EncryptedSharedPreferences, iOS Keychain, which are encrypted and gated by the secure enclave/lock state. Never put credentials in plain preferences or files." },
    { id: 'mbfc_kvfile_4', q: 'Why did platforms move from synchronous prefs (SharedPreferences) to async (DataStore)?', a: "Synchronous preference reads/writes can block the main thread and silently corrupt on concurrent access, causing jank and ANRs. Modern APIs (Jetpack DataStore) are asynchronous and transactional, exposing values as observable flows so reads never block the UI thread and writes are consistent. The lesson: even ‘small’ disk access should be off the main thread." },
  ],
  'local-databases': [
    { id: 'mbfc_localdb_1', q: 'When do you actually need a local database instead of files or key-value?', a: "When data is structured and you must query, filter, sort, relate, or paginate it — messages, feed items, offline records — or when it is too large to load wholesale. A database gives indexed queries, transactions, and partial reads. SQLite underlies most options (Room on Android, GRDB/Core Data on iOS, plus Realm/SQLDelight cross-platform).", hint: 'Need queries, relations, or partial reads.' },
    { id: 'mbfc_localdb_2', q: 'Why must database work never run on the main thread?', a: "Disk I/O and query execution have unpredictable latency; running them on the UI thread freezes the app and triggers ANRs/jank, especially as the DB grows. All reads and writes go on background threads/coroutines, delivering results back to the UI thread. Modern ORMs enforce this (Room rejects main-thread queries by default)." },
    { id: 'mbfc_localdb_3', q: 'What are database migrations and why are they critical on mobile?', a: "Schema changes (new columns/tables) between app versions require migrations that transform existing on-device data to the new shape. Unlike a server DB, you cannot log into a user’s phone — a broken migration corrupts data or crashes on launch for real users. Migrations must be tested against every prior schema version and never silently drop user data." },
    { id: 'mbfc_localdb_4', q: 'How should the UI consume a local database to stay consistent?', a: "By observing it reactively: the DB is the single source of truth and exposes queries as observable streams (Room Flow/LiveData, Core Data fetched results, Realm live objects). Writes update the DB, and every observing screen re-renders automatically. This avoids manual refresh, keeps all screens in sync, and pairs perfectly with declarative UI." },
  ],
  'offline-first': [
    { id: 'mbfc_offline_1', q: 'What does ‘offline-first’ actually mean architecturally?', a: "The local store is the primary source the UI reads from and writes to; the network is a background sync mechanism that fills and flushes that store. The app works fully offline, feels instant (no spinner waiting on the network), and treats connectivity as an enhancement rather than a requirement. The server becomes an eventually-consistent replica partner, not a gatekeeper.", hint: 'The local DB is primary; network syncs it.' },
    { id: 'mbfc_offline_2', q: 'Why is offline-first often better UX even when the user is online?', a: "Reads hit local storage instantly with no network latency, and writes apply optimistically to the local store so the UI updates immediately while sync happens in the background. The result feels fast and reliable on flaky mobile networks, avoids spinners, and degrades gracefully when connectivity drops — the app never feels ‘broken’ because the bus went into a tunnel." },
    { id: 'mbfc_offline_3', q: 'What is optimistic UI and what must you handle when using it?', a: "Applying a user’s action to local state and UI immediately, before the server confirms, then reconciling when the response arrives. You must handle failure: roll back or mark the item if the server rejects it, avoid duplicate submissions on retry (idempotency), and surface unsynced/failed state clearly. Optimism without rollback and reconciliation creates lies in the UI." },
    { id: 'mbfc_offline_4', q: 'What is an outbox / pending-operations queue in offline-first apps?', a: "A durable local queue of writes made while offline (or unconfirmed) that a sync worker replays to the server when connectivity returns, marking each done or failed. It makes local writes reliable across app restarts and process death, enables retry with backoff, and is the backbone of ‘your message will send when you’re back online’ behavior." },
  ],

  // ─── P5 · Networking on Mobile ───────────────────────────────────────────────
  'mobile-request-lifecycle': [
    { id: 'mbfc_reqlife_1', q: 'What are the stages of a network request on mobile, end to end?', a: "Build the request → check connectivity/policy → DNS resolve → TCP/QUIC connect → TLS handshake → send request → wait (server + network latency) → receive/stream response → parse → cache → deliver to UI. On mobile each step can be slow or fail (radio wakeup, high latency, mid-flight drop), so every stage needs timeouts and error handling.", hint: 'DNS → connect → TLS → send → wait → parse.' },
    { id: 'mbfc_reqlife_2', q: 'Why is the first request after idle unusually slow on cellular?', a: "The radio powers down to save battery when idle; the next request must wake it and renegotiate a connection (radio state promotion), adding hundreds of milliseconds before any bytes flow. Plus a cold DNS/TLS handshake. This is why batching requests and reusing connections (keep-alive, HTTP/2 multiplexing) matters far more on mobile than on wired networks." },
    { id: 'mbfc_reqlife_3', q: 'Why does every mobile request need explicit timeouts, and which ones?', a: "Because a mobile connection can stall indefinitely (dead zone, captive portal) and a hung request holds resources and blocks the user. Set connect timeout (establishing the connection), read/response timeout (waiting for data), and an overall/call timeout. Without them a flaky network turns into a frozen feature. Pair timeouts with cancellation when the user leaves the screen." },
    { id: 'mbfc_reqlife_4', q: 'Why must in-flight requests be cancelled when the user navigates away?', a: "A request tied to a screen that is gone wastes battery and bandwidth, and delivering its result can update a destroyed UI or leak memory. Tie request lifetime to the screen/component lifecycle (structured concurrency, cancellation tokens) so leaving a screen cancels its pending work automatically — critical for fast-scrolling lists that fire and abandon many requests." },
  ],
  'flaky-network-design': [
    { id: 'mbfc_flaky_1', q: 'What is the core mindset for networking on mobile?', a: "Assume the network is slow, intermittent, and will fail — design for failure as the normal case, not the exception. Every call can time out, drop mid-response, or return an error; connectivity flips as the user moves. Robust apps show cached content instantly, retry transient failures intelligently, queue writes, and communicate state clearly instead of assuming success.", hint: 'The network WILL fail; plan for it.' },
    { id: 'mbfc_flaky_2', q: 'What is exponential backoff with jitter and why both parts?', a: "On a failed retry, wait an exponentially increasing delay (1s, 2s, 4s...) so you do not hammer a struggling server, and add random jitter so many clients that failed together do not all retry in sync and cause a thundering-herd spike. Cap the max delay and total attempts. It is the standard, server-friendly retry strategy for transient failures." },
    { id: 'mbfc_flaky_3', q: 'Which failures should you retry, and which should you not?', a: "Retry transient/idempotent failures: timeouts, connection drops, 5xx, 429 (respect Retry-After). Do NOT blindly retry non-idempotent writes (a payment) without an idempotency key, or client errors like 400/401/403/404 that will fail again. Distinguishing transient from permanent, and safe from unsafe-to-retry, prevents duplicate side effects and wasted attempts." },
    { id: 'mbfc_flaky_4', q: 'Why are idempotency keys essential for mobile writes?', a: "A request can succeed on the server but the response gets lost to a dropped connection, so the client retries and would create a duplicate (double charge, duplicate post). An idempotency key lets the server recognize the retry as the same operation and return the original result instead of repeating the side effect. On flaky mobile networks, retries are inevitable — idempotency makes them safe." },
  ],
  'image-loading-caching': [
    { id: 'mbfc_imgcache_1', q: 'Why is image loading one of the biggest performance concerns on mobile?', a: "Images are large to download (bandwidth/battery), expensive to decode (CPU), and huge in memory once decoded (a full-res photo can be tens of MB of bitmap). Done naively in a scrolling list they cause jank, memory spikes, and out-of-memory kills. Correct image loading — async, cached, resized, recycled — is often the difference between a smooth and a broken feed.", hint: 'Download + decode + huge in-memory bitmaps.' },
    { id: 'mbfc_imgcache_2', q: 'What are the layers of image caching and why have both?', a: "A memory cache (fast, RAM-limited, for images currently/recently on screen) and a disk cache (slower, larger, survives restarts, avoids re-downloading). A request checks memory → disk → network in order. Two tiers give instant re-display while scrolling back plus offline/repeat-launch savings, without holding every image in scarce RAM." },
    { id: 'mbfc_imgcache_3', q: 'Why must you downsample images to the view size before display?', a: "Decoding a 4000px image into a 200px thumbnail wastes memory proportional to the pixel count (16x the width = 256x the memory) and CPU, and can OOM the app. Decode/resize to the target dimensions (sampling) so the bitmap matches what is shown. Libraries (Glide, Coil, SDWebImage, Kingfisher) do this plus caching, async decode, and request cancellation." },
    { id: 'mbfc_imgcache_4', q: 'Why should list image requests be cancellable and tied to the row?', a: "In a fast-scrolling list, rows are recycled quickly; if a slow image request completes after its row was reused, it sets the wrong image (‘image flickering into the wrong cell’) and wastes work. Binding the request to the row and cancelling it on recycle prevents wrong-image bugs and saves bandwidth/CPU. Good image libraries handle this cancellation for you." },
  ],
  'tls-cert-pinning': [
    { id: 'mbfc_tls_1', q: 'What does TLS give you, and what does it NOT protect against by default?', a: "TLS encrypts traffic and authenticates the server via a certificate chain trusted by the device’s CA store, preventing eavesdropping and tampering in transit. But it trusts ANY certificate the device trusts — so a malicious or compromised CA, a user-installed root, or a corporate proxy can present a valid-looking cert and man-in-the-middle you. Plain TLS trusts the whole CA ecosystem.", hint: 'Encrypts + authenticates, but trusts all CAs.' },
    { id: 'mbfc_tls_2', q: 'What is certificate pinning and what threat does it stop?', a: "The app hardcodes (pins) the expected server certificate or public key and rejects any connection that does not match — even if the presented cert is otherwise validly signed by a trusted CA. This defeats man-in-the-middle via rogue/compromised CAs and traffic interception on the device, which is essential for high-security apps like banking and payments." },
    { id: 'mbfc_tls_3', q: 'What is the operational risk of certificate pinning, and how is it mitigated?', a: "If the pinned cert rotates or expires and the app pins only one key, every installed app instantly loses connectivity until users update — a self-inflicted outage. Mitigations: pin the public key (survives cert renewal), pin multiple keys including a backup, pin an intermediate CA, and ship remote-updatable pin sets with sane expiry. Pinning trades resilience for security and must be operationally planned." },
    { id: 'mbfc_tls_4', q: 'Why is pinning not a silver bullet against a determined attacker on a rooted device?', a: "On a rooted/jailbroken device with a hooking framework (Frida, objection), an attacker can patch the app to bypass pinning checks entirely. Pinning stops network-level MITM but not an attacker with full control of the device. It is one layer; it must be combined with root/jailbreak detection, obfuscation, and server-side defenses — defense in depth, not a single wall." },
  ],

  // ─── P6 · Concurrency & Background Work ───────────────────────────────────────
  'threading-models': [
    { id: 'mbfc_thread_1', q: 'What is the fundamental threading model of a mobile app?', a: "One main/UI thread runs an event loop and owns all UI; background threads/pools do everything slow (I/O, parsing, computation). Work is dispatched to background threads and results are posted back to the main thread to update the UI. Every framework wraps this pattern differently, but the two-world model — UI thread plus workers — is universal.", hint: 'One UI thread + a pool of workers.' },
    { id: 'mbfc_thread_2', q: 'Why are raw threads discouraged in favor of higher-level concurrency?', a: "Manual threads are error-prone: leaks (threads outliving the screen), unbounded creation exhausting resources, race conditions, and no easy cancellation. Higher-level tools — coroutines/dispatchers, async/await, thread pools/executors, GCD queues — provide structured lifetimes, cancellation, backpressure, and safe main-thread hand-off, eliminating whole classes of concurrency bugs." },
    { id: 'mbfc_thread_3', q: 'What is a race condition and why is it common in mobile apps?', a: "When two concurrent operations access shared mutable state and the result depends on timing — e.g. a background result updating a model while the UI reads it. Mobile apps constantly juggle network callbacks, DB writes, and UI updates across threads, so unsynchronized shared state corrupts silently. Fixes: confine mutable state to one thread, use immutable data, or synchronize access." },
    { id: 'mbfc_thread_4', q: 'What is thread confinement and why does it simplify concurrency?', a: "Restricting a piece of mutable state to be accessed from only one thread (e.g. UI state only on the main thread) so no locking is needed and races are impossible by construction. It is why UI is main-thread-only and why actor/isolate models exist. Confinement plus immutable messages between threads is far easier to reason about than shared locked state." },
  ],
  'background-execution-limits': [
    { id: 'mbfc_bglimits_1', q: 'Why do mobile OSes aggressively restrict background execution?', a: "To protect battery and memory for the foreground experience. Apps left free to run in the background would drain battery, hold memory, and wake radios constantly. So the OS suspends backgrounded apps quickly and only permits background work through metered, policy-controlled mechanisms. ‘My code just keeps running in the background’ is not how mobile works.", hint: 'Battery and memory belong to the foreground.' },
    { id: 'mbfc_bglimits_2', q: 'What are the sanctioned ways to do background work, by intent?', a: "Deferrable, guaranteed-eventually work (sync, upload) → WorkManager / BGTaskScheduler, batched by the OS. Immediate user-visible ongoing work (navigation, playback) → foreground service (Android) / background modes (iOS). Time-sensitive server-triggered work → push notifications. Exact-time alarms → restricted alarm APIs. You pick the mechanism that matches the work’s urgency and visibility." },
    { id: 'mbfc_bglimits_3', q: 'What are Android Doze and iOS low-power/App Nap, and how do they affect you?', a: "Power-saving modes the OS enters when the device is idle: they defer background tasks, batch network access into maintenance windows, and restrict wakeups and alarms. Your background jobs may be delayed far longer than requested. You must design background work to be deferrable and idempotent, and use high-priority push only for genuinely urgent, user-relevant events." },
    { id: 'mbfc_bglimits_4', q: 'Why can’t you rely on a background timer to do periodic work?', a: "Once suspended, your process is frozen — timers do not fire, and even scheduled jobs are batched/delayed by Doze/App Nap to save battery. The OS decides when deferrable work actually runs, coalescing it with other apps’ work. For periodic work you register a job with the scheduler and accept OS-controlled, best-effort timing rather than precise intervals." },
  ],
  'foreground-services': [
    { id: 'mbfc_fgsvc_1', q: 'What is a foreground service and when is it the right tool?', a: "An Android mechanism for ongoing, user-aware work that must keep running while the app is backgrounded — music playback, navigation, active fitness/location tracking, a file upload. It shows a persistent notification so the user knows it is running, and in exchange the OS lets it keep executing and holding resources. It is for user-visible ongoing tasks, not silent background work.", hint: 'Ongoing, user-visible, with a notification.' },
    { id: 'mbfc_fgsvc_2', q: 'Why does a foreground service require a persistent notification?', a: "Transparency and accountability: the user must be able to see (and stop) anything consuming battery/resources in the background. The notification is the OS-enforced price for continued execution, preventing apps from silently running forever. Newer Android versions also require declaring a typed foreground-service purpose (location, media, etc.)." },
    { id: 'mbfc_fgsvc_3', q: 'How does iOS handle the use cases Android covers with foreground services?', a: "iOS has no general foreground service; instead it grants specific background modes (audio, location, VoIP, external accessory) that let apps run for those declared purposes, plus background task assertions for finishing short work. The philosophies differ: Android grants a general escape hatch with a notification; iOS grants narrow, purpose-scoped capabilities. Both gate long-running background work tightly." },
    { id: 'mbfc_fgsvc_4', q: 'What is the common mistake with foreground services and background work?', a: "Abusing a foreground service to run arbitrary background work (analytics, sync) just to dodge background limits, which burns battery, annoys users with a permanent notification, and increasingly gets rejected or restricted by the OS/stores. Deferrable work belongs in WorkManager; foreground services are only for genuinely ongoing, user-facing tasks." },
  ],
  'push-notifications-pipeline': [
    { id: 'mbfc_push_1', q: 'Why can’t your server just connect directly to the device to push a message?', a: "Because a suspended app has no live socket, and keeping one open would drain battery. Instead, the OS maintains ONE persistent system connection shared by all apps — FCM on Android, APNs on iOS — and your server hands messages to that service, which wakes the right app. Centralizing the connection is what makes push battery-efficient.", hint: 'One OS socket for all apps: FCM/APNs.' },
    { id: 'mbfc_push_2', q: 'Trace a push notification end to end.', a: "The app registers with FCM/APNs and gets a device token, which it sends to your server. To notify, your server calls FCM/APNs with that token and payload. The push service routes it over its persistent connection to the device, which wakes your app or displays the notification. Delivery is best-effort, not guaranteed or instant. Token → server → FCM/APNs → device.", hint: 'Register → token → server → push service → device.' },
    { id: 'mbfc_push_3', q: 'What is the difference between notification (display) and data/silent push?', a: "A notification message tells the OS to display an alert even if the app is not running (the system handles UI). A data/silent push wakes the app in the background to run brief code (fetch new content, sync) without necessarily showing anything. Silent/background push is heavily throttled by the OS and never guaranteed, so it cannot be your only sync mechanism." },
    { id: 'mbfc_push_4', q: 'Why is push delivery best-effort, and what should you never assume?', a: "The device may be offline, in Doze/low-power, the OS may throttle or coalesce pushes, tokens rotate/expire, and users can revoke permission. So a push may arrive late, once, or never. Never treat push as a reliable transport for critical data — use it as a hint to sync from your server (source of truth), handle token refresh, and design for missed/duplicate notifications." },
  ],

  // ─── P7 · Device Capabilities & Integration ──────────────────────────────────
  'permission-model': [
    { id: 'mbfc_perm_1', q: 'How does the mobile permission model work at a high level?', a: "Sensitive capabilities (location, camera, mic, contacts, notifications) are protected; the app declares what it may use and must request runtime consent from the user, who can grant, deny, or later revoke it. Denial is a normal state you must handle. Permissions are per-capability, revocable at any time in settings, and increasingly granular (e.g. approximate vs precise location).", hint: 'Declare → request at runtime → user grants/denies/revokes.' },
    { id: 'mbfc_perm_2', q: 'Why must you request permissions in context (just-in-time), not all at launch?', a: "Users deny permissions they do not understand; asking for the camera the moment you need it (with clear rationale) dramatically improves grant rates and trust. Front-loading a wall of permission dialogs at launch is jarring and gets denied. Request each permission right when the feature that needs it is used, after explaining why." },
    { id: 'mbfc_perm_3', q: 'What must your app do when a permission is denied or revoked?', a: "Degrade gracefully: keep working without the feature, explain what is unavailable and why, and offer a path to settings if the user changes their mind — never crash, nag repeatedly, or block the whole app. Since permissions can be revoked while the app is backgrounded, always re-check permission state before using a protected capability, not just once." },
    { id: 'mbfc_perm_4', q: 'What are modern granular permission trends you must design for?', a: "Approximate vs precise location, one-time (‘only this time’) grants, ‘while using the app’ vs ‘always’ background access, per-photo/selected-media access instead of the whole library, and required notification opt-in. The trend is user control and data minimization: request the least you need, at the coarsest level that works, and handle partial grants (e.g. approximate-only location)." },
  ],
  'location-maps': [
    { id: 'mbfc_loc_1', q: 'What are the ways to get location and how do they trade accuracy for battery?', a: "GPS/GNSS: most accurate outdoors, slowest to fix, highest battery. Wi-Fi and cell-tower triangulation: coarse but fast and cheap. Fused/network providers blend sensors to balance accuracy and power. You request an accuracy/priority level appropriate to the task — coarse for ‘city’, precise only for turn-by-turn — because location is one of the biggest battery drains.", hint: 'GPS = accurate but hungry; network = coarse but cheap.' },
    { id: 'mbfc_loc_2', q: 'Why is background location the most sensitive and restricted permission?', a: "Continuous background location reveals a user’s life patterns (home, work, habits), so OSes gate it behind a separate, explicit ‘always allow’ grant, show ongoing indicators, and stores scrutinize its justification heavily. It also drains battery fast. Request background/always location only when a core feature truly needs it (navigation, geofencing) and justify it clearly." },
    { id: 'mbfc_loc_3', q: 'What is geofencing and why is it more battery-efficient than polling location?', a: "Geofencing registers regions of interest with the OS, which uses low-power hardware/sensor fusion to notify your app on enter/exit — without your app continuously running GPS. It offloads monitoring to the system, so you get location-triggered behavior (‘remind me at the store’) at a fraction of the battery cost of your app polling GPS in a loop." },
    { id: 'mbfc_loc_4', q: 'What patterns keep continuous location tracking battery-friendly?', a: "Request the lowest sufficient accuracy, throttle update frequency and use distance filters, batch/defer uploads instead of streaming each fix, stop updates when the screen/feature is inactive, and prefer geofencing or significant-location-change APIs over constant high-accuracy GPS. Treat every GPS fix as expensive and ask for the fewest, coarsest fixes the feature can tolerate." },
  ],
  'sensors-biometrics': [
    { id: 'mbfc_sensor_1', q: 'What categories of sensors do mobile devices expose, and what for?', a: "Motion (accelerometer, gyroscope for orientation, steps, gestures), environmental (light, proximity, barometer), position (magnetometer/compass, GPS), and biometric hardware (fingerprint, face). Apps read them via system APIs to power features like auto-rotation, fitness tracking, AR, and secure authentication — always mindful that high-rate sampling costs battery.", hint: 'Motion, environment, position, biometric.' },
    { id: 'mbfc_sensor_2', q: 'How should you consume high-frequency sensor streams responsibly?', a: "Request the lowest sample rate that works, register listeners only while the relevant screen/feature is active and unregister immediately after, process samples off the main thread, and batch where possible. Leaving a sensor (or GPS) registered after the screen is gone is a classic battery-drain and leak bug. Sensors, like location, are start/stop resources tied to lifecycle." },
    { id: 'mbfc_sensor_3', q: 'How does biometric authentication (fingerprint/face) actually keep data safe?', a: "The biometric data never leaves a dedicated secure hardware element (Secure Enclave / TEE / StrongBox); the OS only tells your app pass/fail and can gate access to keys stored in the hardware keystore behind a successful biometric prompt. Your app never sees the fingerprint/face template. You get a trust signal and hardware-gated crypto, not the raw biometric." },
    { id: 'mbfc_sensor_4', q: 'What is the right way to use biometrics for app authentication?', a: "Use the OS biometric prompt to unlock a hardware-keystore-protected secret or token, not as a boolean you check yourself. Always provide a fallback (device PIN/password) since biometrics can fail or be unavailable, and treat biometrics as local device unlock, not as your server-side identity — the server still authenticates via tokens the biometric prompt releases." },
  ],
  'native-interop': [
    { id: 'mbfc_interop_1', q: 'Why do cross-platform apps still need native interop (bridges/plugins/FFI)?', a: "Because some capabilities live only in native SDKs or new OS APIs the framework has not wrapped yet — a payment SDK, a device-specific feature, or a performance-critical routine. Interop lets your cross-platform code call into Kotlin/Swift/C. React Native uses native modules/JSI, Flutter uses platform channels/FFI, so you can drop to native exactly where needed.", hint: 'Reach native SDKs the framework hasn’t wrapped.' },
    { id: 'mbfc_interop_2', q: 'What is the performance cost of crossing the native boundary, and why care?', a: "Marshalling data across the language/runtime boundary (serialize, cross, deserialize) has per-call overhead; doing it in a tight loop or per-frame (e.g. per scroll event) creates a bottleneck. The rule: cross the bridge coarsely — batch calls, pass compact data, and keep chatty back-and-forth off the hot path. Newer designs (JSI, FFI) reduce but do not eliminate this cost." },
    { id: 'mbfc_interop_3', q: 'What responsibilities come with writing native modules for a cross-platform app?', a: "You now maintain platform-specific code twice (Android and iOS), handle threading correctly on each side (never block the UI thread, marshal results back safely), map errors and types across the boundary, and keep the native SDKs updated. Native modules reintroduce the platform differences cross-platform was meant to hide — use them deliberately, not by default." },
    { id: 'mbfc_interop_4', q: 'How do you decide when to write native code vs staying in the framework?', a: "Drop to native only when the framework genuinely cannot do it: unavailable OS/SDK APIs, hard performance requirements, or platform-specific UX that must be pixel-native. Otherwise stay in shared code for velocity. The goal is to keep the native surface small and well-isolated behind a clean interface, so most of the app remains single-codebase." },
  ],

  // ─── P8 · Security & Privacy ──────────────────────────────────────────────────
  'mobile-threat-model': [
    { id: 'mbfc_threat_1', q: 'How is the mobile threat model different from a server’s?', a: "On mobile the attacker often controls the device: they can root/jailbreak it, inspect app storage, decompile your binary, hook functions at runtime, and intercept network traffic. The client is fundamentally untrusted. So secrets cannot be safely hidden in the app, and every security-critical decision must ultimately be enforced server-side.", hint: 'Assume the attacker owns the device.' },
    { id: 'mbfc_threat_2', q: 'What are the main attack surfaces of a mobile app?', a: "Data at rest (files, databases, logs, backups on the device), data in transit (network interception/MITM), the binary itself (reverse engineering, tampering, repackaging), runtime (hooking/instrumentation on rooted devices), IPC and deep-link entry points (malicious input from other apps), and the auth/session layer (stolen tokens). Threat modeling means checking each surface deliberately." },
    { id: 'mbfc_threat_3', q: 'Why must security-critical logic never live only on the client?', a: "Because a determined attacker can decompile, modify, and re-sign the app, or hook it at runtime, bypassing any client-side check (‘is premium’, ‘is allowed’, price calculations). Client checks are UX conveniences; the server must independently authorize every sensitive action. Trusting the client for authorization is the root cause of many mobile breaches." },
    { id: 'mbfc_threat_4', q: 'What is defense in depth in a mobile context?', a: "Layering defenses so no single bypass compromises everything: secure storage for secrets, TLS plus pinning for transport, root/jailbreak detection and obfuscation to raise attacker cost, minimal data collection, and — crucially — server-side authorization as the backstop. Each layer is defeatable alone; together they make attacks expensive and limit blast radius." },
  ],
  'secure-storage-mobile': [
    { id: 'mbfc_securestore_1', q: 'Where do secrets (tokens, keys) belong on a mobile device?', a: "In the hardware-backed secure store: iOS Keychain and Android Keystore, which store keys in a secure element/TEE, gate them behind device unlock/biometrics, and make raw key material non-exportable. Never store credentials in plain preferences, files, source code, or logs. The keystore is the one place designed to hold secrets on an untrusted device.", hint: 'Keychain / Keystore — hardware-backed.' },
    { id: 'mbfc_securestore_2', q: 'Why is embedding an API key or secret in the app binary insecure?', a: "The binary ships to every device and can be decompiled or memory-dumped, so any ‘hidden’ string, key, or endpoint is extractable — obfuscation only slows this down. Hardcoded secrets are effectively public. Sensitive operations must use short-lived, server-issued tokens or move the secret operation server-side; treat the client as a place secrets cannot hide." },
    { id: 'mbfc_securestore_3', q: 'What is the risk of app backups and logs for sensitive data?', a: "Automatic cloud/local backups and verbose logs can silently exfiltrate tokens, PII, or keys off the secure store into places that are easier to read. Exclude sensitive files from backup, never log secrets or PII, and prefer keystore-held items (which are not backed up in plaintext). Data leaks often happen through these side channels, not the primary store." },
    { id: 'mbfc_securestore_4', q: 'How does the OS protect keystore secrets even if the app storage is copied?', a: "Keys are generated and used inside secure hardware and never leave it in plaintext; the app gets a handle to perform crypto, not the key bytes. Access can be bound to device unlock, biometrics, and ‘this device only’, so copying the app’s files to another device or extracting storage does not yield usable keys. That hardware binding is the whole point of using the keystore." },
  ],
  'mobile-auth': [
    { id: 'mbfc_auth_1', q: 'Why should mobile apps use OAuth/OIDC tokens instead of storing a password?', a: "Storing the raw password is dangerous (it is long-lived and grants full access) and unnecessary. Token flows exchange credentials once for a short-lived access token plus a refresh token, so the password is never persisted, access can be scoped and expired quickly, and sessions can be revoked server-side. Tokens limit blast radius if the device is compromised.", hint: 'Never store the password; store scoped tokens.' },
    { id: 'mbfc_auth_2', q: 'What is the access-token/refresh-token split and why use it?', a: "The access token is short-lived and sent on each request; the refresh token is longer-lived and used only to silently obtain new access tokens. This limits exposure (a leaked access token expires fast), avoids re-prompting the user constantly, and lets the server revoke a session by invalidating the refresh token. Store both in the secure keystore, never in plain storage." },
    { id: 'mbfc_auth_3', q: 'Why is PKCE required for OAuth in mobile (public) clients?', a: "Mobile apps cannot keep a client secret (the binary is extractable), making them ‘public clients’ vulnerable to authorization-code interception via a malicious app claiming the redirect. PKCE adds a per-request code verifier/challenge so an intercepted auth code is useless without the original verifier held by the legitimate app. It is the standard fix for OAuth on devices." },
    { id: 'mbfc_auth_4', q: 'How should tokens be handled at rest and in transit on mobile?', a: "At rest: in the hardware keystore (Keychain/Keystore), never in preferences, files, or logs. In transit: only over TLS (ideally pinned). Refresh proactively before expiry, rotate refresh tokens, and clear tokens on logout/uninstall where possible. Also support server-side revocation so a lost device can be cut off. Treat tokens as the crown jewels of the session." },
  ],
  'owasp-mobile-top10': [
    { id: 'mbfc_owasp_1', q: 'What is the OWASP Mobile Top 10 and why reference it?', a: "A community-maintained list of the most common, high-impact mobile security risks — things like improper credential usage, insecure data storage, insufficient transport security, weak authentication/authorization, insecure communication, and code tampering. It is a practical checklist to audit an app against known real-world failure modes rather than guessing at threats.", hint: 'A checklist of the most common mobile risks.' },
    { id: 'mbfc_owasp_2', q: 'Which OWASP mobile risks come down to ‘trusting the client’?', a: "Improper credential usage, insufficient authentication/authorization, and inadequate supply-chain/code integrity all stem from putting trust or secrets on a device the attacker controls. The recurring fix is the same: keep secrets in secure hardware, enforce authorization server-side, validate inputs from IPC/deep links, and never rely on client-side checks for security decisions." },
    { id: 'mbfc_owasp_3', q: 'What are the most common data-at-rest and data-in-transit failures?', a: "At rest: storing tokens/PII in plaintext preferences, files, logs, or backups instead of the keystore. In transit: missing/weak TLS, ignoring cert validation, or accepting user-installed CAs, enabling MITM. Both are among the top OWASP mobile risks and both have direct fixes — hardware-backed secure storage and properly validated (optionally pinned) TLS." },
    { id: 'mbfc_owasp_4', q: 'How do you actually use the OWASP mobile guidance in a project?', a: "Treat it as a review gate: map each risk to your app, verify a control exists (secure storage, transport security, auth, input validation on deep links/IPC, anti-tampering, minimal logging), and complement it with the OWASP MASVS/MASTG for structured verification and testing. It turns ‘are we secure?’ into a concrete, auditable checklist tied to known attacks." },
  ],
  'root-jailbreak-detection': [
    { id: 'mbfc_root_1', q: 'Why does a rooted/jailbroken device weaken your app’s security guarantees?', a: "Root/jailbreak removes the OS sandbox and privilege boundaries, so an attacker can read your app’s private storage, dump memory, bypass keystore protections in some cases, and inject/hook code at runtime with tools like Frida. Assumptions the platform normally enforces no longer hold, which is why high-security apps detect and react to compromised devices.", hint: 'The sandbox and OS guarantees no longer hold.' },
    { id: 'mbfc_root_2', q: 'What does root/jailbreak detection actually check, and why is it imperfect?', a: "It looks for signs of compromise: known su binaries/paths, unexpected write access, hooking frameworks, emulator artifacts, and signature/integrity mismatches. It is imperfect because it runs on the very device it is trying to judge — an attacker with root can hide artifacts or patch out the checks. It raises attacker cost and catches casual cases; it is not a guarantee." },
    { id: 'mbfc_root_3', q: 'What is the right way to respond to a detected compromised device?', a: "Depends on risk tolerance: a banking app may block sensitive actions or refuse to run; a consumer app may just limit high-risk features or increase server-side scrutiny. Crucially, the decision and enforcement should involve the server (via attestation), since a client-only block is bypassable. Balance security against alienating power users on rooted-but-legitimate devices." },
    { id: 'mbfc_root_4', q: 'What is hardware/platform attestation and why is it stronger than local checks?', a: "Attestation (Play Integrity / SafetyNet on Android, App Attest/DeviceCheck on iOS) has secure hardware and platform servers cryptographically vouch for device and app integrity, and your server verifies that signed attestation. Because the signal is rooted in hardware and validated server-side, it is far harder to forge than an in-app check the attacker can patch. It shifts trust off the compromised client." },
  ],

  // ─── P9 · Performance, Testing & Observability ───────────────────────────────
  'mobile-profiling': [
    { id: 'mbfc_profile_1', q: 'What is the golden rule of mobile performance work?', a: "Measure before optimizing, on real low-end devices, not on your flagship or an emulator. Performance intuition is usually wrong; profilers show where time, memory, and battery actually go. Optimize the measured bottleneck, then re-measure. Guessing wastes effort on non-problems and misses the real one — and the median user’s device is far weaker than a developer’s.", hint: 'Measure on real low-end devices first.' },
    { id: 'mbfc_profile_2', q: 'What are the main dimensions you profile on mobile?', a: "Startup time (cold-start to first frame/interactive), UI smoothness (frame times/jank), memory (footprint, leaks, allocation churn/GC), CPU (hot paths, main-thread stalls), network (request count/size/timing), battery/energy, and app size. Tools: Android Studio Profiler/Perfetto/Macrobenchmark, Xcode Instruments, Flutter DevTools. Each dimension has its own tool and target." },
    { id: 'mbfc_profile_3', q: 'Why is memory profiling especially important on mobile?', a: "Because the OS kills high-memory background apps first (hurting warm start and losing state), and leaks or bitmap bloat cause out-of-memory crashes. Watch for leaked screens/contexts (retained after navigation), unbounded caches, and large decoded images. Keeping a lean, stable memory footprint directly improves survival in the background and crash rates." },
    { id: 'mbfc_profile_4', q: 'How do lab benchmarks and field (real-user) metrics differ, and why need both?', a: "Lab benchmarks (Macrobenchmark, Instruments) give repeatable, controlled measurements to catch regressions in CI. Field metrics (Android Vitals, Firebase Performance, crash/ANR rates) capture the messy reality of thousands of real devices and networks you cannot reproduce. Lab catches regressions early; field tells you what users actually experience. You need both to improve real performance." },
  ],
  'mobile-testing-pyramid': [
    { id: 'mbfc_testpyr_1', q: 'What does the testing pyramid look like for a mobile app?', a: "A wide base of fast unit tests (business logic, view models, pure functions), a middle layer of integration tests (DB, networking, repository, component interactions), and a narrow top of end-to-end UI tests on emulators/devices (Espresso, XCUITest, Flutter integration tests, Maestro). Many cheap fast tests, few expensive slow ones — the same shape as any pyramid but with a device layer.", hint: 'Many unit tests, few slow UI/device tests.' },
    { id: 'mbfc_testpyr_2', q: 'Why keep UI/end-to-end tests few relative to unit tests?', a: "Device/UI tests are slow, flaky (timing, animations, emulators), and expensive to maintain, so a suite dominated by them is brittle and slow to run. Push logic into testable, UI-independent layers (view models, use cases) covered by fast unit tests, and reserve a small set of E2E tests for the critical user journeys. Speed and reliability come from the base of the pyramid." },
    { id: 'mbfc_testpyr_3', q: 'What makes mobile apps particularly hard to test, and how do you design for it?', a: "The lifecycle (process death, config changes), device/OS fragmentation, permissions, and network variability create huge state space. You design for testability by separating platform-coupled code from pure logic, injecting dependencies (clock, network, storage) so they can be faked, and testing the risky lifecycle/offline paths explicitly rather than only the happy path." },
    { id: 'mbfc_testpyr_4', q: 'How do you handle device fragmentation in testing?', a: "You cannot test every device manually, so you combine emulators for broad OS-version/API coverage, a small set of real physical devices (especially low-end and different OEMs), and cloud device farms (Firebase Test Lab, BrowserStack, AWS Device Farm) to run automated tests across many models. Prioritize the devices and OS versions your actual user base (from analytics) runs." },
  ],
  'crash-reporting-analytics': [
    { id: 'mbfc_crash_1', q: 'Why is crash reporting non-negotiable for a shipped mobile app?', a: "You cannot see users’ devices, and stores/reviews punish crashes harshly. A crash reporter (Crashlytics, Sentry, Bugsnag) captures stack traces, device/OS/context, and crash-free-user rates from the field, so you learn about and prioritize failures you could never reproduce locally. Without it you are flying blind on the reliability metric users care about most.", hint: 'You can’t reproduce what you can’t see.' },
    { id: 'mbfc_crash_2', q: 'What are ANRs and why must you track them separately from crashes?', a: "An ANR (Application Not Responding) or iOS watchdog termination happens when the main thread is blocked too long — the app freezes rather than crashing with an exception. Users experience it as ‘the app hangs’, stores flag it, but it may not show up as a normal crash. Tracking ANR/hang rates surfaces main-thread-blocking bugs that crash reporters alone can miss." },
    { id: 'mbfc_crash_3', q: 'What is symbolication/deobfuscation and why is it essential for crash reports?', a: "Release builds are minified/obfuscated and native crashes report raw memory addresses, so a raw stack trace is unreadable. Uploading symbol/mapping files (dSYM, ProGuard/R8 mapping) lets the crash tool translate traces back into your real class/method/line names. Without symbolication, crash reports are noise; with it, you can pinpoint the failing line." },
    { id: 'mbfc_crash_4', q: 'What is the difference between crash reporting and product analytics, and why have both?', a: "Crash reporting tells you when/why the app broke (stability). Product analytics (events, funnels, retention) tells you what users do and whether features work (behavior). Together they answer ‘is the app healthy AND useful?’ Both must respect privacy — minimize collected data, avoid PII, honor consent — but you need reliability signals and usage signals to steer the product." },
  ],

  // ─── P10 · Ship, Operate & Choose Your Stack ─────────────────────────────────
  'build-systems-signing': [
    { id: 'mbfc_build_1', q: 'What does code signing do and why does every mobile app require it?', a: "Signing cryptographically ties an app to a developer identity and guarantees the binary has not been tampered with since. The OS refuses to install or run unsigned/altered apps, and updates must be signed by the same key as the original. It underpins app authenticity, secure updates, and store trust — there is no unsigned distribution on iOS, and Android verifies signatures too.", hint: 'Proves who built it and that it’s untampered.' },
    { id: 'mbfc_build_2', q: 'Why is losing your signing key (or Android upload/app-signing key) a serious problem?', a: "Because updates must be signed with the same key as the installed app; a mismatched signature is rejected as a different app, so users cannot upgrade in place — they would have to uninstall and reinstall, losing local data. Keys must be backed up securely and access-controlled. Play App Signing and iOS managed certificates help, but key custody is a real operational risk." },
    { id: 'mbfc_build_3', q: 'What are build variants/flavors and configurations, and why use them?', a: "Ways to produce different builds from one codebase — debug vs release, dev/staging/prod environments, free vs paid, per-brand — with different endpoints, keys, signing, and flags. They let you test against staging safely, ship a hardened release build (minified, no debug logging), and manage multiple product variants without code forks. Build config is a first-class part of mobile engineering." },
    { id: 'mbfc_build_4', q: 'What is the difference between a debug and a release build, beyond ‘optimization’?', a: "A release build is minified/obfuscated (R8/ProGuard, Swift optimizations), strips debug logging and debuggability, enables full compiler optimizations, is signed with the release key, and shrinks/splits assets — so it is smaller, faster, and harder to reverse-engineer. Debug builds prioritize fast iteration and inspectability. Never profile performance or ship security assumptions based on a debug build." },
  ],
  'app-store-submission': [
    { id: 'mbfc_store_1', q: 'What is app store review and what does it gate?', a: "Before an app (or update) reaches users, the store (Apple App Store, Google Play) reviews it against policies: security, privacy/data-use disclosures, content, functionality, and guideline compliance. Apple review is stricter and human-involved; Google mixes automated and manual checks. Approval is required to publish, and violations can get an app rejected or removed — policy is a real engineering constraint.", hint: 'A policy/quality gate before users get the app.' },
    { id: 'mbfc_store_2', q: 'What are the most common reasons apps get rejected?', a: "Privacy issues (undisclosed data collection, missing privacy labels/permissions rationale), crashes/broken features found in review, guideline violations (payments bypassing store billing, misleading metadata), incomplete information for reviewers, and using private/undocumented APIs. Most rejections are avoidable by reading the guidelines and testing the exact build you submit on a clean device." },
    { id: 'mbfc_store_3', q: 'Why must you plan for review latency and store metadata as part of shipping?', a: "Review can take hours to days, so hotfixes are not instant — you cannot patch a critical bug the moment you find it, which is why staged rollout and remote config/feature flags matter. You also must prepare metadata: screenshots, descriptions, privacy nutrition labels/data-safety forms, age ratings, and localized store listings. Shipping is a process, not just uploading a binary." },
    { id: 'mbfc_store_4', q: 'What privacy disclosures do the stores now require, and why do they matter to engineers?', a: "Apple’s privacy nutrition labels and app tracking transparency, and Google Play’s Data Safety section, require you to accurately declare what data you collect, why, and whether you track users across apps. Engineers must actually know what every SDK collects, because inaccurate disclosures cause rejection or removal. Data practices are now a shipping requirement, not an afterthought." },
  ],
  'mobile-cicd': [
    { id: 'mbfc_cicd_1', q: 'What does a mobile CI/CD pipeline automate, and why is it worth it?', a: "On every change: build both platforms, run unit/integration/UI tests (often on emulators or a device farm), lint/static-analyze, sign, and distribute a build to testers or the store track. It catches regressions early, produces reproducible signed builds, and removes error-prone manual steps (signing, versioning, uploading). Manual mobile release is slow and mistake-prone at any real scale.", hint: 'Build → test → sign → distribute, automatically.' },
    { id: 'mbfc_cicd_2', q: 'What makes mobile CI/CD harder than backend CI/CD?', a: "You build two native platforms with heavy toolchains (Xcode requires macOS runners; Android needs the SDK/NDK), manage secure signing credentials in CI, run slow flaky UI tests on emulators/real devices, and cannot instantly deploy — releases go through store review and staged rollout. Signing-secret management and long device-test times are the parts backend pipelines rarely face." },
    { id: 'mbfc_cicd_3', q: 'How are beta/test builds distributed before a public release?', a: "Through internal/closed testing tracks — TestFlight on iOS, Play internal/closed/open testing on Android — or services like Firebase App Distribution. Testers get near-production signed builds to catch issues review and lab testing miss, and you validate the exact artifact you will promote. Staged pre-release testing is how you de-risk before exposing all users." },
    { id: 'mbfc_cicd_4', q: 'Why are versioning and build numbers a real concern in mobile pipelines?', a: "Stores reject uploads with a build/version number not higher than the last, and users/crash reports must map to an exact build. Pipelines auto-increment build numbers, tag releases in source control, and keep version-to-commit traceability so you can symbolicate crashes and know precisely what shipped. Getting versioning wrong blocks uploads and makes production debugging painful." },
  ],
  'choosing-your-stack': [
    { id: 'mbfc_stack_1', q: 'Now that you understand the platform, how should you choose a framework?', a: "By matching the dominant constraint to the tool’s strengths: team skills and hiring, how much you need bleeding-edge OS/hardware integration, performance and UI-fidelity needs, time-to-market across both stores, and long-term maintenance. Since every framework obeys the same lifecycle, threading, and limits you’ve learned, the choice is about ergonomics and fit — not a different set of rules.", hint: 'Match the dominant constraint to the tool.' },
    { id: 'mbfc_stack_2', q: 'When does native (Kotlin/Swift) clearly win over cross-platform?', a: "When you need maximum performance, the latest OS features the day they ship, deep hardware/SDK integration, or truly platform-idiomatic UX — and when you have the team to maintain two codebases. Games, AR/camera-heavy apps, and apps whose whole value is a native experience lean native. The cost is duplicated work across platforms." },
    { id: 'mbfc_stack_3', q: 'When does cross-platform (Flutter/React Native) clearly win?', a: "When shared business logic and fast time-to-market across both stores matter more than squeezing out native-level performance or same-day OS features, when the team already knows JS/Dart, or when a small team must ship and maintain both platforms. Most CRUD/content/commerce apps fit here — you accept an abstraction layer in exchange for a single codebase and velocity." },
    { id: 'mbfc_stack_4', q: 'Why is ‘understand mobile, then any framework is learnable’ the real takeaway?', a: "Because the hard, durable knowledge — lifecycle and process death, the single UI thread, the frame budget, background limits, permissions, secure storage, offline-first networking, and store operations — is identical across Flutter, React Native, Kotlin, and Swift. Frameworks change syntax and rendering strategy; the platform behavior you must respect does not. Master the concepts and you can pick up any stack." },
  ],
}
